*/ namespace Module\Cinema\Admin\Controller; use Illuminate\Routing\Controller; use ModStart\Admin\Concern\HasAdminQuickCRUD; use ModStart\Admin\Layout\AdminCRUDBuilder; use ModStart\Core\Dao\ModelUtil; use ModStart\Form\Form; use ModStart\Grid\GridFilter; use ModStart\Support\Concern\HasFields; use Module\Cinema\AssetAccess\Type\CreditStatus; use Module\Cinema\AssetAccess\Type\FreeStatus; use Module\Cinema\AssetAccess\Type\VipStatus; use Module\Cinema\Type\CinemaShowVideoType; use Module\Member\Util\MemberVipUtil; use Module\Vendor\Provider\VideoStream\VideoStreamField; class CinemaShowController extends Controller { use HasAdminQuickCRUD; protected function crud(AdminCRUDBuilder $UXxZR) { VideoStreamField::register(); $UXxZR->init('cinema_show')->field(function ($UXxZR) { $UXxZR->id('id', 'ID'); $UXxZR->selectRemote('seriesId', '剧集')->server(modstart_admin_url('cinema/series/select_remote'))->viewWithModel('cinema_series')->required(); $UXxZR->number('sort', '排序')->help('留空将自动计算'); $UXxZR->text('title', '名称')->required(); $UXxZR->image('cover', '封面')->required(); $UXxZR->radio('freeStatus', '付费')->optionType(FreeStatus::class)->defaultValue(FreeStatus::FREE)->listable(true)->when('=', FreeStatus::FEE, function ($UXxZR) { $UXxZR->radio('vipStatus', 'VIP特权')->optionType(VipStatus::class)->defaultValue(VipStatus::DISABLE)->when('=', VipStatus::ENABLE, function ($UXxZR) { $UXxZR->checkbox('vipIds', 'VIP')->options(MemberVipUtil::mapTitle()); }); $UXxZR->radio('creditStatus', '积分购买')->optionType(CreditStatus::class)->defaultValue(CreditStatus::DISABLE)->when('=', CreditStatus::ENABLE, function ($UXxZR) { $UXxZR->number('creditCost', '积分')->defaultValue(0); }); })->required(); $UXxZR->radio('videoType', '播放类型')->optionType(CinemaShowVideoType::class)->when('=', CinemaShowVideoType::LOCAL, function ($UXxZR) { $UXxZR->file('videoPath', '视频文件')->listable(false)->help('只支持MP4格式'); })->when('=', CinemaShowVideoType::CLOUD, function ($UXxZR) { $UXxZR->videoStream('videoCloud', '视频')->scope('admin')->listable(false); })->defaultValue(CinemaShowVideoType::LOCAL)->required(); $UXxZR->radio('tryVideoType', '试看类型')->optionType(CinemaShowVideoType::class)->when('=', CinemaShowVideoType::LOCAL, function ($UXxZR) { $UXxZR->file('tryVideoPath', '视频')->listable(false)->help('只支持MP4格式'); })->when('=', CinemaShowVideoType::CLOUD, function ($UXxZR) { $UXxZR->videoStream('tryVideoCloud', '视频')->scope('admin')->listable(false); })->defaultValue(CinemaShowVideoType::LOCAL)->required(); $UXxZR->display('created_at', L('Created At'))->listable(false); $UXxZR->display('updated_at', L('Updated At'))->listable(false); })->hookSaved(function (Form $GtTXi) { $LKQ89 = $GtTXi->item(); if (empty($LKQ89->sort)) { ModelUtil::update('cinema_show', $LKQ89->id, array('sort' => ModelUtil::sortNext('cinema_show', array('seriesId' => $LKQ89->seriesId)))); } })->gridFilter(function (GridFilter $UGzyw) { $UGzyw->eq('id', L('ID')); $UGzyw->eq('seriesId', '剧集ID'); $UGzyw->like('title', L('Title')); })->title('视频管理'); } }